#include <iostream>
#include <sstream>
#include <string>
#include <unordered_set>
#include <vector>

int main() {
    std::string line;
    std::getline(std::cin, line);
    std::istringstream iss(line);

    std::vector<int> result;
    std::unordered_set<int> seen;
    int x;

    while (iss >> x) {
        if (seen.find(x) == seen.end()) {
            seen.insert(x);
            result.push_back(x);
        }
    }

    for (size_t i = 0; i < result.size(); ++i) {
        if (i > 0) std::cout << ' ';
        std::cout << result[i];
    }
    std::cout << '\n' << result.size() << '\n';

    return 0;
}
